mapper.insert:
INSERT INTO bluenote_comment.user_comment (
    id, comment_id, user_id, note_id, root_id, parent_comment_id,
    comment_status, content_preview, note_title_snapshot, note_cover_url_snapshot,
    created_at, updated_at
) VALUES (
    #{id}, #{commentId}, #{userId}, #{noteId}, #{rootId}, #{parentCommentId},
    #{commentStatus}, #{contentPreview}, #{noteTitleSnapshot}, #{noteCoverUrlSnapshot},
    #{createdAt}, #{updatedAt}
)

mapper.update:
UPDATE bluenote_comment.user_comment
SET comment_status = 'DELETED',
    updated_at = #{updatedAt}
WHERE comment_id = #{commentId}
  AND comment_status = 'VISIBLE'

UPDATE bluenote_comment.user_comment
SET comment_status = 'DELETED',
    updated_at = #{updatedAt}
WHERE root_id = #{rootId}
  AND comment_status = 'VISIBLE'

mapper.select:
SELECT id, comment_id, user_id, note_id, root_id, parent_comment_id,
       comment_status, content_preview, note_title_snapshot, note_cover_url_snapshot,
       created_at, updated_at
FROM bluenote_comment.user_comment
WHERE user_id = #{userId}

  AND (
    created_at < #{cursorCreatedAt}
    OR (created_at = #{cursorCreatedAt} AND comment_id < #{cursorCommentId})
  )

ORDER BY created_at DESC, comment_id DESC
LIMIT #{size}
